class Solution:
    def greatestLetter(self, s: str) -> str:
        upper = set()
        lower = set()
        for char in s:
            if char.isupper():
                upper.add(char)
            else:
                lower.add(char)
        greatest = ''
        for char in upper:
            if char.lower() in lower:
                if greatest == '' or char > greatest:
                    greatest = char
        return greatest
```
